import _ from 'lodash';
import { ActionTree } from 'vuex';
import { type } from '@/data/constans';
import { SET_CURRENTDATA } from './mutation-types';

const actions: ActionTree<any, any> = {
  selectCard({ state, commit }: any, user: {
  num: number, type: string, name: string,
  levelXiu: number, levelDu: number, levelJu: number
  }) {
    const { currentData } = state;
    const newData = [...currentData];
    const oldRen = _.find(currentData[user.num], { type: type.ren_wu });
    const oldFa = _.find(currentData[user.num], { type: type.fa_bao });
    // console.log('oldRen:', oldRen)
    // console.log('oldFa:', oldFa)
    newData[user.num] = [];
    if (user.type === type.ren_wu) {
      newData[user.num].push(user);
      if (oldFa) {
        newData[user.num].push(oldFa);
      }
    }
    if (user.type === type.fa_bao) {
      if (oldRen) {
        newData[user.num].push(oldRen);
      }
      newData[user.num].push(user);
    }
    // console.log('user:', user)
    // console.log('newData:', newData)
    commit(SET_CURRENTDATA, newData);
  },
};

export default actions;
